import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { analysisAPI } from "../services/api";
import Navbar from "../components/Navbar";

const QUICK = ["JavaScript","Python","React","Node.js","TypeScript","MongoDB","SQL","Docker","AWS","Machine Learning","TensorFlow","Git","DSA","System Design","CSS","Express","PostgreSQL","Linux","Redis","Kubernetes"];

export default function Analysis() {
  const nav = useNavigate();
  const [mode, setMode] = useState("manual");
  const [input, setInput] = useState("");
  const [skills, setSkills] = useState([]);
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const add = (s) => {
    const sk = s.trim();
    if (sk && !skills.map(x=>x.toLowerCase()).includes(sk.toLowerCase())) setSkills([...skills, sk]);
    setInput("");
  };

  const analyze = async () => {
    setLoading(true); setError(""); setResult(null);
    try {
      let r;
      if (mode === "resume" && file) {
        r = await analysisAPI.resume(file);
        setSkills(r.data.extractedSkills || []);
        setResult(r.data.analysis);
      } else {
        if (!skills.length) { setError("Add at least one skill"); setLoading(false); return; }
        r = await analysisAPI.analyze(skills);
        setResult(r.data.analysis);
      }
    } catch (e) {
      setError(e.response?.data?.message || "Analysis failed — ensure all 3 services are running.");
    } finally { setLoading(false); }
  };

  const pctColor = p => p>=70 ? "var(--green)" : p>=40 ? "var(--amber)" : "var(--red)";

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg)", color:"var(--text)" }}>
      <Navbar/>
      <div style={{ maxWidth:950, margin:"0 auto", padding:"2rem 1.5rem" }}>
        <h1 className="sg-section-title" style={{ marginBottom:".4rem" }}>🔍 Skill Analysis</h1>
        <p style={{ color:"var(--muted)", marginBottom:"2rem", fontSize:".9rem" }}>AI predicts your top career matches and shows exactly what to learn next.</p>

        {/* Input */}
        <div className="sg-card" style={{ marginBottom:"1.5rem" }}>
          <div style={{ display:"flex", gap:".4rem", marginBottom:"1.2rem", background:"var(--bg)", borderRadius:10, padding:4 }}>
            {["manual","resume"].map(m => (
              <button key={m} onClick={() => setMode(m)} style={{ flex:1, padding:".55rem", borderRadius:8, border:"none", fontWeight:600, fontSize:".85rem", cursor:"pointer", fontFamily:"inherit", background: mode===m ? "linear-gradient(135deg,var(--blue),#6c63ff)" : "transparent", color: mode===m ? "#fff" : "var(--muted)", transition:"all .2s" }}>
                {m === "manual" ? "✏️ Manual Input" : "📄 Upload Resume PDF"}
              </button>
            ))}
          </div>

          {mode === "manual" && (
            <>
              <div style={{ display:"flex", gap:".5rem", marginBottom:"1rem" }}>
                <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"||e.key===","){e.preventDefault();add(input);}}} placeholder='Type a skill and press Enter (e.g. "React", "Python")...' className="sg-input" style={{ flex:1 }}/>
                <button onClick={()=>add(input)} className="sg-btn sg-btn-primary sg-btn-sm">Add</button>
              </div>
              <div style={{ marginBottom:".8rem" }}>
                <p style={{ color:"var(--muted)", fontSize:".76rem", marginBottom:".4rem" }}>Quick add:</p>
                <div style={{ display:"flex", flexWrap:"wrap", gap:".3rem" }}>
                  {QUICK.filter(s=>!skills.map(x=>x.toLowerCase()).includes(s.toLowerCase())).map(s => (
                    <button key={s} onClick={()=>add(s)} style={{ background:"var(--bg3)", color:"var(--muted)", border:"1px solid var(--border)", borderRadius:20, padding:".18rem .6rem", fontSize:".76rem", cursor:"pointer", transition:"all .15s" }}
                      onMouseEnter={e=>{e.target.style.color="var(--blue)";e.target.style.borderColor="var(--blue)";}}
                      onMouseLeave={e=>{e.target.style.color="var(--muted)";e.target.style.borderColor="var(--border)";}}>
                      +{s}
                    </button>
                  ))}
                </div>
              </div>
              {skills.length > 0 && (
                <div style={{ display:"flex", flexWrap:"wrap", gap:".35rem", padding:".75rem", background:"var(--bg)", borderRadius:10, border:"1px solid var(--border)", minHeight:48 }}>
                  {skills.map(s => (
                    <span key={s} className="sg-tag sg-tag-blue">
                      {s}
                      <button onClick={()=>setSkills(skills.filter(x=>x!==s))} style={{ background:"none", border:"none", color:"var(--red)", cursor:"pointer", padding:0, lineHeight:1, fontSize:"1rem" }}>×</button>
                    </span>
                  ))}
                </div>
              )}
            </>
          )}

          {mode === "resume" && (
            <>
              <input type="file" accept=".pdf" onChange={e=>setFile(e.target.files[0])} style={{ display:"none" }} id="rf"/>
              <label htmlFor="rf" style={{ display:"block", padding:"2.5rem", border:"2px dashed var(--border)", borderRadius:12, textAlign:"center", cursor:"pointer" }}
                onMouseEnter={e=>e.currentTarget.style.borderColor="var(--blue)"}
                onMouseLeave={e=>e.currentTarget.style.borderColor="var(--border)"}>
                {file ? (
                  <><div style={{ fontSize:"2rem", marginBottom:".4rem" }}>✅</div>
                  <p style={{ color:"var(--green)", fontWeight:600 }}>{file.name}</p>
                  <p style={{ color:"var(--muted)", fontSize:".8rem" }}>Click to change</p></>
                ) : (
                  <><div style={{ fontSize:"2rem", marginBottom:".4rem" }}>📄</div>
                  <p style={{ color:"var(--muted)", fontWeight:600 }}>Click to upload PDF resume</p>
                  <p style={{ color:"var(--muted)", fontSize:".8rem" }}>We extract your skills with NLP automatically</p></>
                )}
              </label>
            </>
          )}

          {error && <div style={{ marginTop:"1rem", background:"rgba(252,129,129,.08)", border:"1px solid rgba(252,129,129,.3)", borderRadius:8, padding:".7rem 1rem", color:"var(--red)", fontSize:".85rem" }}>⚠️ {error}</div>}

          <button onClick={analyze} disabled={loading||(mode==="resume"&&!file)} className="sg-btn sg-btn-primary" style={{ width:"100%", justifyContent:"center", marginTop:"1.2rem", padding:"1rem" }}>
            {loading ? "⏳ Running AI Analysis..." : "🚀 Analyze My Skills"}
          </button>
        </div>

        {/* Results */}
        {result && (
          <div className="fade-up">
            {/* Top Match */}
            <div className="sg-card" style={{ marginBottom:"1rem", borderColor:"rgba(61,142,240,.3)" }}>
              <div style={{ display:"flex", justifyContent:"space-between", flexWrap:"wrap", gap:"1rem" }}>
                <div>
                  <p style={{ color:"var(--muted)", fontSize:".78rem", marginBottom:".3rem" }}>🎯 TOP CAREER MATCH</p>
                  <h2 style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:"1.8rem", color:"var(--blue)", marginBottom:".3rem" }}>{result.top_match?.job_role}</h2>
                  <p style={{ color:"var(--muted)", fontSize:".88rem", maxWidth:500 }}>{result.top_match?.description}</p>
                  <p style={{ color:"var(--green)", fontSize:".85rem", marginTop:".4rem", fontWeight:600 }}>💰 {result.top_match?.avg_salary} · {result.top_match?.demand_level} demand</p>
                  <p style={{ color:"var(--muted)", fontSize:".78rem" }}>Career: {result.top_match?.career_path}</p>
                </div>
                <div style={{ textAlign:"center", background:"var(--bg)", border:"1px solid var(--border)", borderRadius:12, padding:"1rem 1.5rem" }}>
                  <div style={{ fontFamily:"'Syne',sans-serif", fontSize:"2.5rem", fontWeight:900, color:pctColor(result.top_match?.match_percentage) }}>{result.top_match?.match_percentage?.toFixed(0)}%</div>
                  <div style={{ color:"var(--muted)", fontSize:".75rem" }}>Match Score</div>
                  <button onClick={() => nav("/roadmap", { state: { role: result.top_match?.job_role } })} className="sg-btn sg-btn-primary sg-btn-sm" style={{ marginTop:".6rem" }}>View Roadmap →</button>
                </div>
              </div>
            </div>

            {/* All predictions */}
            <div className="sg-card" style={{ marginBottom:"1rem" }}>
              <h3 style={{ fontWeight:700, marginBottom:"1rem", fontSize:".95rem", color:"var(--muted)" }}>ALL CAREER MATCHES</h3>
              {result.predictions?.map((p,i) => (
                <div key={i} style={{ display:"flex", alignItems:"center", gap:".8rem", padding:".55rem 0", borderBottom:"1px solid var(--border)" }}>
                  <span style={{ color:"var(--muted)", fontWeight:700, minWidth:24, fontSize:".82rem" }}>#{i+1}</span>
                  <span style={{ flex:1, fontWeight:600, fontSize:".88rem" }}>{p.job_role}</span>
                  <div className="match-bar"><div className="match-fill" style={{ width:`${p.match_percentage}%` }}/></div>
                  <span style={{ minWidth:36, textAlign:"right", fontWeight:700, color:pctColor(p.match_percentage), fontSize:".9rem" }}>{p.match_percentage.toFixed(0)}%</span>
                </div>
              ))}
            </div>

            {/* Skill breakdown */}
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit,minmax(240px,1fr))", gap:"1rem", marginBottom:"1rem" }}>
              {[
                { t:"✅ Matching", sk:result.analysis?.matching_skills,   cls:"sg-tag-green" },
                { t:"❌ Missing",  sk:result.analysis?.missing_skills,    cls:"sg-tag-red" },
                { t:"⚠️ Irrelevant",sk:result.analysis?.irrelevant_skills,cls:"sg-tag-amber" },
              ].map(({t,sk,cls}) => (
                <div key={t} className="sg-card">
                  <h4 style={{ fontSize:".88rem", fontWeight:700, marginBottom:".7rem" }}>{t} ({sk?.length||0})</h4>
                  <div style={{ display:"flex", flexWrap:"wrap", gap:".3rem" }}>
                    {sk?.length ? sk.map(s => <span key={s} className={`sg-tag ${cls}`}>{s}</span>) : <span style={{ color:"var(--muted)", fontSize:".82rem" }}>None</span>}
                  </div>
                </div>
              ))}
            </div>

            {/* Learning path preview */}
            {result.learning_path?.length > 0 && (
              <div className="sg-card" style={{ marginBottom:"1rem" }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"1rem" }}>
                  <h3 style={{ fontWeight:700 }}>🗺️ Learning Path ({result.learning_path.length} skills)</h3>
                  <button onClick={()=>nav("/study-plan")} className="sg-btn sg-btn-outline sg-btn-sm">Full Plan →</button>
                </div>
                <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(165px,1fr))", gap:".5rem" }}>
                  {result.learning_path.slice(0,8).map((s,i) => (
                    <div key={i} style={{ background:"var(--bg)", border:"1px solid var(--border)", borderRadius:10, padding:".7rem", display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                      <div>
                        <div style={{ fontWeight:600, fontSize:".85rem" }}>{s.skill}</div>
                        <div style={{ color: s.difficulty==="Beginner"?"var(--green)":s.difficulty==="Intermediate"?"var(--amber)":"var(--red)", fontSize:".7rem" }}>{s.difficulty} · {s.estimated_hours}h</div>
                      </div>
                      <span style={{ color:"var(--muted)" }}>→</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Readiness */}
            {result.readiness && (
              <div className="sg-card" style={{ borderColor:"rgba(159,122,234,.3)" }}>
                <h3 style={{ fontWeight:700, marginBottom:"1rem" }}>🎯 Interview Readiness</h3>
                <div style={{ display:"flex", justifyContent:"space-between", flexWrap:"wrap", gap:"1rem" }}>
                  <div>
                    <div style={{ fontFamily:"'Syne',sans-serif", fontSize:"2.5rem", fontWeight:900, color:pctColor(result.readiness.score) }}>{result.readiness.score}%</div>
                    <div style={{ color:"var(--purple)", fontWeight:600 }}>{result.readiness.level}</div>
                    <button onClick={()=>nav("/interview")} className="sg-btn sg-btn-purple sg-btn-sm" style={{ marginTop:".6rem" }}>Start Interview Prep →</button>
                  </div>
                  <div style={{ flex:1, minWidth:200 }}>
                    {Object.entries(result.readiness.breakdown||{}).map(([k,v]) => (
                      <div key={k} style={{ display:"flex", gap:".6rem", alignItems:"center", marginBottom:".4rem" }}>
                        <span style={{ color:"var(--muted)", fontSize:".78rem", minWidth:120, textTransform:"capitalize" }}>{k.replace(/_/g," ")}</span>
                        <div className="sg-progress" style={{ flex:1 }}><div className="sg-bar" style={{ width:`${v}%` }}/></div>
                        <span style={{ color:"var(--purple)", fontSize:".78rem", fontWeight:600, minWidth:20 }}>{v}</span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}
